class TestDiscoverSessions:
    def test_discovers_session_from_fixture(self, tmp_sessions_dir):
        sessions = discover_sessions(sessions_dir=tmp_sessions_dir)
        assert len(sessions) == 1
        assert sessions[0].pid == 12345
        assert sessions[0].session_id == "aaaaaaaa-bbbb-cccc-dddd-eeeeeeeeeeee"
        assert sessions[0].cwd == "C:\\Users\\user\\source\\my-project"

    def test_returns_empty_for_missing_dir(self, tmp_path):
        sessions = discover_sessions(sessions_dir=tmp_path / "nonexistent")
        assert sessions == []

    def test_returns_empty_for_empty_dir(self, tmp_path):
        empty_dir = tmp_path / "sessions"
        empty_dir.mkdir()
        sessions = discover_sessions(sessions_dir=empty_dir)
        assert sessions == []

    def test_skips_malformed_json(self, tmp_path):
        sessions_dir = tmp_path / "sessions"
        sessions_dir.mkdir()
        (sessions_dir / "bad.json").write_text("not json{{{", encoding="utf-8")
        sessions = discover_sessions(sessions_dir=sessions_dir)
        assert sessions == []

    def test_skips_missing_fields(self, tmp_path):
        sessions_dir = tmp_path / "sessions"
        sessions_dir.mkdir()
        (sessions_dir / "1.json").write_text(
            json.dumps({"pid": 0, "sessionId": "", "cwd": "x", "startedAt": 0}),
            encoding="utf-8",
        )
        sessions = discover_sessions(sessions_dir=sessions_dir)
        assert sessions == []

    def test_orders_by_cwd_lexicographically(self, tmp_path):
        sessions_dir = tmp_path / "sessions"
        sessions_dir.mkdir()
        cwds = ["/home/user/source/zebra", "/home/user/source/alpha", "/home/user/source/middle"]
        for i, cwd in enumerate(cwds):
            data = {
                "pid": 100 + i,
                "sessionId": f"session-{i}",
                "cwd": cwd,
                "startedAt": 1000,
            }
            (sessions_dir / f"{100 + i}.json").write_text(json.dumps(data), encoding="utf-8")
        sessions = discover_sessions(sessions_dir=sessions_dir)
        result_cwds = [s.cwd for s in sessions]
        assert result_cwds == sorted(cwds)


